export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const MAIN_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE = 25;
const BLOCK_BASE = 60;
const BLOCK_SIZE = 3;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

interface PricedUnit {
  base: number;
}

function priceItems(items: Item[]): PricedUnit[] {
  const units: PricedUnit[] = [];
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      units.push({ base: MAIN_BASE[item.type] });
    }
  }
  for (const count of Object.values(componentCounts)) {
    if (count === BLOCK_SIZE) {
      units.push({ base: BLOCK_BASE });
    } else {
      for (let i = 0; i < count; i++) units.push({ base: COMPONENT_BASE });
    }
  }
  return units;
}

export function quote(_customer: Customer, items: Item[], _priorContracts: number): number {
  const units = priceItems(items);
  let itemsTotal = 0;
  for (const u of units) {
    itemsTotal += u.base + u.base * FIRST_INSURANCE_RATE;
  }
  return itemsTotal + PROCESSING_FEE;
}

