import { describe, it, expect } from "vitest";
import { quote } from "./claim-office.js";

describe("MHPCO Claim Office — quote", () => {
  // Simplest case
  it("empty item list → premium 5 G (only processing fee)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [], 0)).toBe(5);
  });

  // Base premiums per item type (first insurance surcharge applies to each item)
  it("single sword, no modifiers, new customer → 100 base + 10 first insurance + 5 fee = 115 G", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", material: "steel", enchantment: 0, cursed: false }], 0)).toBe(115);
  });
  it("single amulet, no modifiers, new customer → 60 base + 6 first insurance + 5 fee = 71 G", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }], 0)).toBe(71);
  });
  it("single staff, no modifiers, new customer → 80 base + 8 first insurance + 5 fee = 93 G", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff" }], 0)).toBe(93);
  });
  it("single potion, no modifiers, new customer → 40 base + 4 first insurance + 5 fee = 49 G", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion" }], 0)).toBe(49);
  });

  // Components & building blocks of 3 alike
  it("2 runes → base 50 G, premium 60 G (50 + 5 first ins + 5 fee)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }], 0)).toBe(60);
  });
  it("3 runes → base 60 G (block applies), premium 71 G", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }], 0)).toBe(71);
  });
  it("4 runes → base 100 G (no block — block requires exactly 3), premium 115 G (100 + 10 + 5)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], 0)).toBe(115);
  });
  it("7 runes → base 175 G, premium with first ins each = 175 + 17.5 + 5 = 197.5 → 198 G (rounded up)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, Array(7).fill({ type: "rune" }), 0)).toBe(198);
  });

  // 'Alike' components: same type only
  it("2 runes + 1 moonstone → base 75 G (no block: different types), premium 88 G (75 + 7.5 + 5 = 87.5, rounded up)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }], 0)).toBe(88);
  });
  it("3 runes + 3 moonstones → base 120 G (two separate blocks), premium 137 G (120 + 12 + 5)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [...Array(3).fill({ type: "rune" }), ...Array(3).fill({ type: "moonstone" })], 0)).toBe(137);
  });

  // Item-specific modifier scope
  it("cursed sword + plain amulet (new customer, first contract) → curse adds 50 G to cursed item only; 100+50+10 + 60+6 + 5 = 231 G", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }, { type: "amulet" }], 0)).toBe(231);
  });

  // Modifier thresholds
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("cursed sword with exactly enchantment 5 → both curse and high-enchantment surcharges apply");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");

  // Cursed surcharge
  it.todo("cursed sword (steel, ench 3), new customer (0 years) → 165 G (100 + 50 curse + 10 first ins + 5 fee)");

  // Rounding in MHPCO's favor for premiums
  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");

  // Integration example
  it.todo("long-standing (3y) customer, second quote, cursed sword (ench 7) → 160 G");
});

describe("MHPCO Claim Office — claim", () => {
  // Standard reimbursement
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("rune damaged (insurance 250 G), damage 200 G → payout 100 G (200 - 100 deductible)");

  // High enchantment ≥ 8: 50% reimbursement
  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% = 500, then -100)");

  // Dragon material: full reimbursement
  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full - 100)");

  // Both clauses — high-enchantment wins
  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% rule wins: 500 - 100)");
  it.todo("dragon-material sword, ench exactly 8, damage 1000 G → payout 400 G (high-ench applies, then deductible)");

  // Deductible per damage event
  it.todo("dragon attack on sword (500 G) and amulet (300 G) → payout 600 G (deductible once per item)");

  // Multiple items of same type
  it.todo("policy covers two swords; both damaged → two separate damages each with own deductible");
  it.todo("policy covers one sword but damages array has two sword entries → CLI exits non-zero (claim rejected)");

  // Cap exhaustion
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword policy → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) policy → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword (cap 2000) — first claim 1500 G → payout 1400 G, remainingCap 600 G");
  it.todo("sword (cap 2000) — first claim 1500 G then second claim 1500 G → second payout 600 G, remainingCap 0 G");

  // Rounding in MHPCO's favor for payouts
  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");
});

describe("MHPCO Claim Office — CLI / errors", () => {
  it.todo("quote with unknown item type (e.g. broomstick) → non-zero exit, error on stderr, no results on stdout");
  it.todo("claim references item not part of policy → non-zero exit, error on stderr");
  it.todo("claim references item with unknown type → non-zero exit, error on stderr");
  it.todo("claim contains damage entry with negative amount → non-zero exit, error on stderr");

  // Sequential scenario (CLI integration)
  it.todo("scenario with quote then claim returns results array with premium then {payout, remainingCap}");
});

